function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj: number[][] = new Array(n).fill(0).map(() => new Array<number>());
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Check if a path is a palindrome
    function isPalindrome(path: number[]): boolean {
        const s: string = path.map(i => label[i]).join('');
        return s === s.split('').reverse().join('');
    }

    // Try all possible paths using backtracking
    let maxLength = 0;

    function backtrack(currentPath: number[], visited: boolean[]): void {
        // Check if current path is a palindrome
        if (isPalindrome(currentPath)) {
            maxLength = Math.max(maxLength, currentPath.length);
        }

        // If all nodes are visited, return
        if (currentPath.length === n) {
            return;
        }

        // Try all adjacent nodes
        for (const neighbor of adj[currentPath[currentPath.length - 1]]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                currentPath.push(neighbor);
                backtrack(currentPath, visited);
                currentPath.pop();
                visited[neighbor] = false;
            }
        }
    }

    // Start from each node
    for (let i = 0; i < n; i++) {
        const visited: boolean[] = new Array(n).fill(false);
        visited[i] = true;
        const path: number[] = [i];
        backtrack(path, visited);
    }

    return maxLength;
}

